222	async function checkOpenClawNotifier(
223	  config: OrchestratorConfig,
224	  fail: (msg: string) => void,
225	): Promise<void> {
226	  const openclawConfig = config.notifiers?.["openclaw"];
227	  if (!openclawConfig || openclawConfig.plugin !== "openclaw") {
228	    warn("OpenClaw notifier is not configured. Fix: run ao setup openclaw");
229	    return;
230	  }
231	
232	  const url =
233	    (typeof openclawConfig["url"] === "string" ? openclawConfig["url"] : undefined) ??
234	    "http://127.0.0.1:18789";
235	  // Resolve ${ENV_VAR} placeholders written by `ao setup openclaw` — the config
236	  // stores the literal string "${OPENCLAW_HOOKS_TOKEN}" which is truthy but wrong.
237	  const rawToken = typeof openclawConfig["token"] === "string" ? openclawConfig["token"] : undefined;
238	  const envVarMatch = rawToken?.match(/^\$\{([^}]+)\}$/);
239	  const token = (envVarMatch ? process.env[envVarMatch[1]] : rawToken) ?? process.env["OPENCLAW_HOOKS_TOKEN"];
240	
241	  const installation = await detectOpenClawInstallation(url);
242	  if (installation.state === "running") {
243	    pass(
244	      `OpenClaw gateway detected at ${installation.gatewayUrl} (HTTP ${installation.probe.httpStatus})`,
245	    );
246	  } else if (installation.state === "installed-but-stopped") {
247	    const installHint = installation.binaryPath
248	      ? `installed at ${installation.binaryPath}`
249	      : "configured on this machine";
250	    fail(`OpenClaw is ${installHint} but the gateway is not running at ${installation.gatewayUrl}`);
251	  } else {
252	    fail(
253	      `OpenClaw is not installed locally and the gateway is not reachable at ${installation.gatewayUrl}. ` +
254	        `Fix: install/start OpenClaw or update the notifier URL`,
255	    );
256	  }
257	
258	  // Step 2: Validate auth token if present
259	  if (!token) {
260	    warn(
261	      "OpenClaw token is not set. Fix: set OPENCLAW_HOOKS_TOKEN env var or add token to notifiers.openclaw in config",
262	    );
263	  } else if (installation.state === "running") {
264	    const tokenResult = await validateToken(installation.gatewayUrl, token);
265	    if (!tokenResult.valid) {
266	      fail(`OpenClaw token validation failed: ${tokenResult.error}`);
267	    } else {
268	      pass("OpenClaw token is valid");
269	    }
270	  }
271	
272	  const health = readOpenClawHealth(config);
273	  if (!health) {
274	    warn("No OpenClaw notification history recorded yet");
275	    return;
276	  }
277	
278	  const lastSuccess = formatTimestamp(health.lastSuccessAt);
279	  if (lastSuccess) {
280	    pass(`OpenClaw last successful notification: ${lastSuccess}`);
281	  } else {
282	    warn("OpenClaw has not recorded a successful notification yet");
283	  }
284	
285	  if (health.lastFailureAt) {
286	    const lastFailure = formatTimestamp(health.lastFailureAt);
287	    warn(
288	      `OpenClaw last failure: ${lastFailure ?? health.lastFailureAt} (${health.lastFailureError ?? "unknown error"})`,
289	    );
290	  }
291	
292	  pass(`OpenClaw notification totals: ${health.totalSent} sent, ${health.totalFailed} failed`);
293	}
