303	  if (configuredNotifiers.length === 0) {
304	    warn("No notifiers are configured. Fix: add notifiers to your agent-orchestrator.yaml");
305	    return;
306	  }
307	
308	  // Check OpenClaw specifically (it's the only one we can probe without side effects)
309	  if (config.notifiers?.["openclaw"]) {
310	    await checkOpenClawNotifier(config, fail);
311	  }
312	
313	  // Report other configured notifiers as present (we can't health-check Slack/desktop/webhook without sending)
314	  for (const [name, notifierConfig] of Object.entries(config.notifiers ?? {})) {
315	    if (name === "openclaw") continue; // already checked above
316	    const plugin = notifierConfig.plugin;
317	    pass(`${name} notifier is configured (plugin: ${plugin})`);
318	  }
319	}
