324	
325	async function sendTestNotifications(
326	  config: OrchestratorConfig,
327	  registry: PluginRegistry,
328	  fail: (msg: string) => void,
329	): Promise<void> {
330	  const activeNotifierNames = config.defaults?.notifiers ?? [];
331	  const targets = new Map<string, ReturnType<typeof resolveNotifierTarget>>();
332	
333	  for (const name of Object.keys(config.notifiers ?? {})) {
334	    targets.set(name, resolveNotifierTarget(config, name));
335	  }
336	
337	  for (const name of activeNotifierNames) {
338	    const target = resolveNotifierTarget(config, name);
339	    if (!targets.has(target.reference)) {
340	      targets.set(target.reference, target);
341	    }
342	  }
343	
344	  if (targets.size === 0) {
345	    warn("No notifiers to test. Fix: configure notifiers in your agent-orchestrator.yaml");
346	    return;
347	  }
348	
349	  console.log(`\nSending test notification to ${targets.size} notifier(s)...\n`);
350	
351	  for (const target of targets.values()) {
352	    const notifier =
353	      registry.get<Notifier>("notifier", target.reference) ??
354	      registry.get<Notifier>("notifier", target.pluginName);
355	    if (!notifier) {
356	      warn(`${target.reference}: plugin "${target.pluginName}" not loaded (may not be installed)`);
357	      continue;
358	    }
359	
360	    try {
361	      const testEvent = {
362	        id: `doctor-test-${Date.now()}`,
363	        type: "summary.all_complete" as const,
364	        priority: "info" as const,
365	        sessionId: "doctor-test",
366	        projectId: "doctor",
367	        timestamp: new Date(),
368	        message: "Test notification from ao doctor --test-notify",
369	        data: { source: "ao-doctor" },
370	      };
371	
372	      await notifier.notify(testEvent);
373	      pass(`${target.reference}: test notification sent`);
374	    } catch (err) {
375	      const message = err instanceof Error ? err.message : String(err);
376	      fail(`${target.reference}: ${message}`);
377	    }
378	  }
379	}
380	
381	// ---------------------------------------------------------------------------
382	// Version freshness (cache-only — no network call)
383	// ---------------------------------------------------------------------------
384	
385	function checkVersionFreshness(): void {
386	  console.log("");
387	  console.log("Version:");
388	
389	  const current = getCurrentVersion();
390	  const cached = readCachedUpdateInfo();
391	
392	  if (!cached) {
393	    pass(`ao v${current} installed (run any ao command to check for updates)`);
394	    return;
395	  }
396	
397	  if (isVersionOutdated(current, cached.latestVersion)) {
398	    warn(`ao v${current} is outdated (latest: v${cached.latestVersion}). Run: ao update`);
399	  } else {
400	    pass(`ao v${current} is the latest version`);
401	  }
402	}
403	
404	// ---------------------------------------------------------------------------
405	// Command registration
406	// ---------------------------------------------------------------------------
407	
408	export function registerDoctor(program: Command): void {
409	  program
410	    .command("doctor")
411	    .description("Run install, environment, and runtime health checks")
412	    .option("--fix", "Apply safe fixes for launcher and stale temp issues")
413	    .option("--test-notify", "Send a test notification through each configured notifier")
414	    .action(async (opts: { fix?: boolean; testNotify?: boolean }) => {
415	      const { fail, count: failCount } = makeFailCounter();
416	
417	      // 1. Run shell checks
418	      const scriptArgs: string[] = [];
419	      if (opts.fix) {
420	        scriptArgs.push("--fix");
421	      }
422	
423	      let shellExitCode: number;
424	      try {
425	        shellExitCode = await runRepoScript("ao-doctor.sh", scriptArgs);
426	      } catch (err) {
427	        console.error(err instanceof Error ? err.message : String(err));
428	        shellExitCode = 1;
429	      }
430	
431	      // 2. Version freshness (cache-only, no network dependency)
432	      checkVersionFreshness();
433	
434	      // 3. Run TypeScript-based notifier checks if a config file exists
435	      const configPath = findConfigFile();
436	      if (configPath) {
437	        let config: ReturnType<typeof loadConfig> | undefined;
438	        let registry: PluginRegistry | undefined;
439	        try {
440	          config = loadConfig(configPath);
441	          registry = await checkPluginResolution(config, fail);
442	          await checkNotifierConnectivity(config, fail);
443	        } catch (err) {
444	          const message = err instanceof Error ? err.message : String(err);
445	          fail(`Config-aware doctor checks failed: ${message}`);
446	        }
447	
448	        // 4. Send test notifications if requested (separate catch for accurate errors)
449	        if (opts.testNotify && config && registry) {
450	          try {
451	            await sendTestNotifications(config, registry, fail);
452	          } catch (err) {
453	            const message = err instanceof Error ? err.message : String(err);
454	            fail(`Sending test notifications failed: ${message}`);
455	          }
456	        }
457	      } else if (opts.testNotify) {
458	        fail("No config file found. Cannot test notifiers without agent-orchestrator.yaml");
459	      }
460	
461	      // Exit non-zero if shell checks or notifier checks failed
462	      if (shellExitCode !== 0 || failCount() > 0) {
463	        process.exit(shellExitCode || 1);
464	      }
465	    });
466	}
